@page "/apply"
@rendermode InteractiveServer
@using sv_b76d20d39e654664b8d2acc4a361bf34.Models
@inject IApplicationService AppService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="text-center mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   OnStepClicked="GoToStep" />

    <div class="mt-4">
        @switch (currentStep)
        {
            case 0:
                <PersonalInfoStep @ref="personalInfoStep"
                                  Model="personalInfo"
                                  OnNext="AdvanceFromPersonalInfo"
                                  OnValidateEmail="ValidateAndAdvanceEmail" />
                break;

            case 1:
                <WorkHistoryStep Entries="workEntries"
                                 OnNext="() => GoToNext()"
                                 OnBack="GoToPrevious" />
                break;

            case 2:
                <ReferencesStep References="references"
                                OnNext="() => GoToNext()"
                                OnBack="GoToPrevious" />
                break;

            case 3:
                <CoverLetterStep @bind-CoverLetter="coverLetter"
                                 OnNext="() => GoToNext()"
                                 OnBack="GoToPrevious" />
                break;

            case 4:
                <ReviewStep Personal="personalInfo"
                            WorkEntries="workEntries"
                            References="references"
                            CoverLetter="coverLetter"
                            OnEditSection="GoToStep"
                            OnBack="GoToPrevious"
                            OnSubmit="SubmitApplication"
                            IsSubmitting="isSubmitting"
                            Submitted="submitted"
                            ApplicationId="applicationId"
                            ErrorMessage="@submitError" />
                break;
        }
    </div>
</div>

@code {
    private int currentStep;
    private readonly HashSet<int> completedSteps = new();

    // Form state
    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = new() { new WorkEntryModel() };
    private List<ReferenceModel> references = new() { new ReferenceModel(), new ReferenceModel() };
    private string coverLetter = "";

    // Submission state
    private bool isSubmitting;
    private bool submitted;
    private int applicationId;
    private string? submitError;

    // Component refs
    private PersonalInfoStep? personalInfoStep;

    private void AdvanceFromPersonalInfo()
    {
        GoToNext();
    }

    private async Task ValidateAndAdvanceEmail(string? email)
    {
        if (string.IsNullOrWhiteSpace(email)) return;

        var isValid = await AppService.ValidateEmailAsync(email);
        if (!isValid)
        {
            personalInfoStep?.SetError("Please enter a valid email address.");
            return;
        }

        GoToNext();
    }

    private void GoToNext()
    {
        completedSteps.Add(currentStep);
        currentStep = Math.Min(currentStep + 1, 4);
    }

    private void GoToPrevious()
    {
        currentStep = Math.Max(currentStep - 1, 0);
    }

    private void GoToStep(int step)
    {
        if (completedSteps.Contains(step) || step == currentStep)
            currentStep = step;
    }

    private async Task SubmitApplication()
    {
        isSubmitting = true;
        submitError = null;

        try
        {
            var application = new JobApplication(
                personalInfo.ToRecord(),
                new WorkHistory(workEntries.Select(e => e.ToRecord()).ToList()),
                references.Select(r => r.ToRecord()).ToList(),
                coverLetter
            );

            applicationId = await AppService.SubmitApplicationAsync(application);
            submitted = true;
        }
        catch (Exception ex)
        {
            submitError = $"Submission failed: {ex.Message}. Please try again.";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

